;self:updatePosition(currentRow,currentCol)if currentRow==20 and self.EndRace then self:updateStatus("Row 20! Tweening to EndRace...")if self.activeTween then self.activeTween:Cancel()self.activeTween=nil end;rootPart.AssemblyLinearVelocity=Vector3.zero;local tweenInfo=TweenInfo.new(0.35,Enum.EasingStyle.Quad,Enum.EasingDirection.Out)local tween=TweenService:Create(rootPart,tweenInfo,{CFrame=self.EndRace.CFrame*CFrame.new(0,3.5,0)})tween:Play()tween.Completed:Wait()local confirmed=false;for i=1,15 do if self.RaceBlocker and self.RaceBlocker.CanCollide then confirmed=true;break end;task.wait(0.1)end;if confirmed then self:updateStatus("Victory! Waiting for new round...")break else self:updateStatus("Not confirmed, resuming path...")self:scanGrid()local newRow,newCol=self:getPlayerPosition()if newRow then currentRow,currentCol=newRow,newCol end end end;local path=self:findPath(currentRow,currentCol)if#path<2 then self:updateStatus("Path not found")task.wait(0.3)self:scanGrid()shouldRestart=true;break end;local nextNode=path[2]local cells=self:getRowCells(nextNode.row)local cell=cells and cells[nextNode.col]local button=cell and self:getCellButton(cell)if not button then task.wait(0.1)shouldRestart=true;break end;local targetCFrame=CFrame.new(button.Position+Vector3.new(0,3,0))rootPart.AssemblyLinearVelocity=Vector3.zero;local tweenComplete=false;local tweenCancelled=false;task.spawn(function()self:tweenToPosition(rootPart,targetCFrame,self.tweenSpeed)tweenComplete=true end)local elapsed=0;while not tweenComplete do if self.isStunned or not self.botRunning or(self.RaceBlocker and self.RaceBlocker.CanCollide)then if self.activeTween then self.activeTween:Cancel()self.activeTween=nil end;tweenCancelled=true;break end;task.wait(0.016)elapsed=elapsed+0.016;if elapsed>self.tweenSpeed+0.5 then break end end;if not self.botRunning then break end;if tweenCancelled then task.wait(0.05)shouldRestart=true;break end;task.wait(0.05)if self.isStunned then shouldRestart=true;break en