botRunning=true;self:updateStatus("Wall gone — new round!")task.spawn(function()self:runBot()end)else self:updateStatus("Ready")end end;task.wait(0.2)end end)end;function MinefieldBot:SetupUI(tab)self.parentTab=tab or Event;self.statusLabel=self.parentTab:CreateTextLabel("Status: Waiting...")self.posLabel=self.parentTab:CreateTextLabel("Pos: --")self.parentTab:CreateSavedSlider("Bot Tween Speed","minefield_bot_speed",{Min=10,Max=50,Default=35},function(Value)self.tweenSpeed=Value/100 end)self.parentTab:CreateSavedToggle("Auto Run Minefield","auto_run_minefield",function(State)self.botRunning=State;if State then self.raceFinished=false;task.spawn(function()self:runBot()end)else self.raceFinished=false;if self.activeTween then self.activeTween:Cancel()self.activeTween=nil end;self:updateStatus("Bot Paused..")end end)end;function MinefieldBot:Start()if not self:Initialize()then return false end;self:startStunDetection()self:startWallObserver()return true end;function MinefieldBot:Stop()self.isRunning=false;self.botRunning=false;if self.activeTween then self.activeTween:Cancel()self.activeTween=nil end;self:updateStatus("Bot Stopped")end;getgenv().MinefieldBot=MinefieldBot;return MinefieldBot
